#include <stdio.h>
#include <stdlib.h>

int max(int a, int b) {
    return a > b ? a : b;
}

int main() {
    int n, m;
    scanf("%d %d", &n, &m);

    int min_answer = n + max(m - n, 0);
    int max_answer = n + max(0, m - 1);

    if (n == 0 && m == 0) {
        printf("0 0\n");
        return 0;
    }

    if (n == 0) {
        printf("Impossible\n");
        return 0;
    }

    printf("%d %d\n", min_answer, max_answer);
    return 0;
}
